import React, { useState, useMemo } from 'react';
import Header from './components/Header';
import MatchCard from './components/MatchCard';
import LeagueFilter from './components/LeagueFilter';
import { generateMatches } from './data/mockData';

const App = () => {
  const [activeView, setActiveView] = useState("predictions");
  const [selectedLeague, setSelectedLeague] = useState("all");
  const [searchTerm, setSearchTerm] = useState("");

  const matches = useMemo(() => generateMatches(), []);

  const filteredMatches = useMemo(() => {
    let filtered = [...matches];

    if (selectedLeague !== "all") {
      filtered = filtered.filter(m => m.leagueName === selectedLeague);
    }

    if (searchTerm.trim() !== "") {
      const term = searchTerm.toLowerCase();
      filtered = filtered.filter(m => 
        m.homeTeam.toLowerCase().includes(term) || 
        m.awayTeam.toLowerCase().includes(term) ||
        m.leagueName.toLowerCase().includes(term)
      );
    }

    return filtered;
  }, [matches, selectedLeague, searchTerm]);

  const groupedMatches = useMemo(() => {
    const groups = {};
    filteredMatches.forEach(match => {
      if (!groups[match.leagueName]) groups[match.leagueName] = [];
      groups[match.leagueName].push(match);
    });
    return groups;
  }, [filteredMatches]);

  const viewTitles = {
    predictions: { title: "🔮 AI Match Predictions", subtitle: "Based on advanced football algorithms" },
    odds: { title: "💰 Best Odds & Comparisons", subtitle: "Latest odds from top bookmakers" },
    stats: { title: "📊 Team Statistics & Form", subtitle: "Head-to-head & season stats" }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <Header activeView={activeView} setActiveView={setActiveView} />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6">
        <LeagueFilter
          selectedLeague={selectedLeague}
          onLeagueChange={setSelectedLeague}
          searchTerm={searchTerm}
          onSearchChange={setSearchTerm}
        />

        {/* View Header */}
        <div className="mb-5">
          <h2 className="text-xl font-bold text-gray-800">
            {viewTitles[activeView].title}
          </h2>
          <p className="text-sm text-gray-500 mt-0.5">
            {viewTitles[activeView].subtitle} • Forebet style
          </p>
        </div>

        {/* Matches Grid */}
        {Object.keys(groupedMatches).length === 0 ? (
          <div className="bg-white rounded-2xl p-12 text-center shadow-sm">
            <div className="text-5xl mb-3">⚽</div>
            <p className="text-gray-500 font-medium">No matches found for this filter</p>
            <button
              onClick={() => {
                setSelectedLeague("all");
                setSearchTerm("");
              }}
              className="mt-3 text-blue-600 text-sm font-semibold hover:text-blue-700"
            >
              Clear filters
            </button>
          </div>
        ) : (
          <div className="space-y-8">
            {Object.entries(groupedMatches).map(([leagueName, leagueMatches]) => (
              <div key={leagueName}>
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-2xl">{leagueMatches[0]?.leagueFlag || "⚽"}</span>
                  <h3 className="font-bold text-lg text-gray-800">{leagueName}</h3>
                  <span className="text-xs bg-gray-200 px-2 py-0.5 rounded-full text-gray-600">
                    {leagueMatches.length} matches
                  </span>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
                  {leagueMatches.map(match => (
                    <MatchCard key={match.id} match={match} viewType={activeView} />
                  ))}
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Footer Stats */}
        <div className="mt-12 bg-gradient-to-r from-blue-50 to-indigo-50 rounded-2xl p-5 border border-blue-100">
          <div className="flex flex-col sm:flex-row items-center justify-between gap-3">
            <div className="flex items-center gap-3">
              <div className="text-3xl">📈</div>
              <div>
                <p className="font-bold text-gray-800">Prediction Accuracy: 74.3%</p>
                <p className="text-xs text-gray-600">
                  Based on Poisson distribution, team form & historical data
                </p>
              </div>
            </div>
            <div className="text-xs bg-white/80 px-4 py-2 rounded-full text-blue-700 font-medium shadow-sm">
              ⚡ Updated live • Next update in 5min
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;
